const PART5_EASY2 = [
  {id:"p5e2_1",question:"The office _____ at 8:30 every weekday morning.",options:["A) open","B) opens","C) opened","D) opening"],answer:"B",explanation:"Third-person singular present simple for regular routines.",category:"Grammar"},
  {id:"p5e2_2",question:"She _____ her laptop at home and had to borrow one.",options:["A) forgets","B) forgot","C) has forgotten","D) forgetting"],answer:"B",explanation:"Simple past for a specific completed event.",category:"Grammar"},
  {id:"p5e2_3",question:"The shipment _____ arrive by Thursday at the latest.",options:["A) shall","B) will","C) must","D) could"],answer:"B",explanation:"'Will arrive' — future simple for an expectation.",category:"Modal"},
  {id:"p5e2_4",question:"We _____ a new supplier after the previous one missed three deadlines.",options:["A) find","B) have found","C) found","D) are finding"],answer:"C",explanation:"Simple past for a completed past action.",category:"Grammar"},
  {id:"p5e2_5",question:"He introduced _____ to the new client at the networking event.",options:["A) him","B) himself","C) his","D) he"],answer:"B",explanation:"Reflexive pronoun 'himself' — the subject and object are the same person.",category:"Grammar"},
  {id:"p5e2_6",question:"The team managed the entire project _____ with no outside help.",options:["A) themselves","B) itself","C) yourself","D) herself"],answer:"A",explanation:"Reflexive 'themselves' for a plural subject (team).",category:"Grammar"},
  {id:"p5e2_7",question:"Please help _____ to the refreshments after the presentation.",options:["A) you","B) yours","C) yourself","D) your"],answer:"C",explanation:"'Help yourself to' is a fixed expression.",category:"Grammar"},
  {id:"p5e2_8",question:"The CEO spoke for _____ in the press conference.",options:["A) herself","B) her","C) she","D) hers"],answer:"A",explanation:"'Spoke for herself' — reflexive for emphasis.",category:"Grammar"},
  {id:"p5e2_9",question:"The company prides _____ on its outstanding customer support.",options:["A) it","B) its","C) itself","D) them"],answer:"C",explanation:"'Pride itself on' — reflexive verb phrase.",category:"Grammar"},
  {id:"p5e2_10",question:"The technician repaired the machine _____ without calling an outside contractor.",options:["A) himself","B) his","C) him","D) he"],answer:"A",explanation:"'Repaired it himself' — reflexive for emphasis.",category:"Grammar"},
  {id:"p5e2_11",question:"Please turn _____ the lights before leaving the office.",options:["A) on","B) off","C) up","D) in"],answer:"B",explanation:"'Turn off the lights' = switch them off.",category:"Phrasal Verb"},
  {id:"p5e2_12",question:"We ran _____ of printer paper, so please order more.",options:["A) short","B) out","C) low","D) off"],answer:"B",explanation:"'Run out of' = have none remaining.",category:"Phrasal Verb"},
  {id:"p5e2_13",question:"The meeting was called _____ due to the director's illness.",options:["A) back","B) out","C) off","D) up"],answer:"C",explanation:"'Called off' = cancelled.",category:"Phrasal Verb"},
  {id:"p5e2_14",question:"Please fill _____ this application form and return it by Friday.",options:["A) in","B) up","C) out","D) both A and C"],answer:"D",explanation:"'Fill in' (British) and 'fill out' (American) both mean to complete a form.",category:"Phrasal Verb"},
  {id:"p5e2_15",question:"Could you look _____ this report and let me know if anything seems wrong?",options:["A) at","B) into","C) over","D) both A and C"],answer:"D",explanation:"'Look at' (check) and 'look over' (review carefully) are both correct.",category:"Phrasal Verb"},
  {id:"p5e2_16",question:"He handed _____ the signed contracts to the legal team.",options:["A) over","B) in","C) out","D) both A and B"],answer:"D",explanation:"'Hand over' (transfer) and 'hand in' (submit) are both correct here.",category:"Phrasal Verb"},
  {id:"p5e2_17",question:"The new manager wants to set _____ a meeting with each team member.",options:["A) up","B) out","C) off","D) in"],answer:"A",explanation:"'Set up a meeting' = arrange/organize it.",category:"Phrasal Verb"},
  {id:"p5e2_18",question:"She was asked to look _____ the junior team while the supervisor was away.",options:["A) after","B) over","C) into","D) at"],answer:"A",explanation:"'Look after' = take care of.",category:"Phrasal Verb"},
  {id:"p5e2_19",question:"The marketing team will come _____ with a new campaign idea by Friday.",options:["A) out","B) up","C) in","D) over"],answer:"B",explanation:"'Come up with' = to produce or think of something.",category:"Phrasal Verb"},
  {id:"p5e2_20",question:"Could you put _____ the call to tomorrow morning?",options:["A) off","B) back","C) through","D) both A and B"],answer:"D",explanation:"'Put off' (delay) and 'put back' (reschedule to later) both work.",category:"Phrasal Verb"},
  {id:"p5e2_21",question:"Please switch _____ your mobile phones during the presentation.",options:["A) off","B) out","C) down","D) over"],answer:"A",explanation:"'Switch off' = turn off completely.",category:"Phrasal Verb"},
  {id:"p5e2_22",question:"The HR department is looking _____ several complaints from employees.",options:["A) over","B) into","C) at","D) after"],answer:"B",explanation:"'Looking into' = investigating.",category:"Phrasal Verb"},
  {id:"p5e2_23",question:"We had to turn _____ the candidate because she lacked the required experience.",options:["A) away","B) down","C) off","D) both A and B"],answer:"D",explanation:"'Turn away' (send away) and 'turn down' (reject) are both valid.",category:"Phrasal Verb"},
  {id:"p5e2_24",question:"The project was held _____ because of budget approval delays.",options:["A) back","B) up","C) off","D) both A and B"],answer:"D",explanation:"'Held back' (delayed) and 'held up' (caused delays) are both correct.",category:"Phrasal Verb"},
  {id:"p5e2_25",question:"The sales team needs to follow _____ with clients after the trade show.",options:["A) up","B) out","C) in","D) through"],answer:"A",explanation:"'Follow up with' = make further contact with someone.",category:"Phrasal Verb"},
  {id:"p5e2_26",question:"The package was too heavy _____ carry alone.",options:["A) for","B) to","C) so","D) that"],answer:"B",explanation:"'Too + adjective + to + infinitive' — standard structure for impossibility.",category:"Grammar"},
  {id:"p5e2_27",question:"This report isn't detailed _____ to submit to the board.",options:["A) so","B) enough","C) too","D) very"],answer:"B",explanation:"'Detailed enough to' — 'enough' follows an adjective.",category:"Grammar"},
  {id:"p5e2_28",question:"The room was _____ small to hold all 200 attendees.",options:["A) very","B) quite","C) too","D) enough"],answer:"C",explanation:"'Too small to hold' — 'too' expresses inability.",category:"Grammar"},
  {id:"p5e2_29",question:"She speaks English well _____ to give the keynote address.",options:["A) enough","B) too","C) very","D) quite"],answer:"A",explanation:"'Speaks well enough to' — sufficiency structure.",category:"Grammar"},
  {id:"p5e2_30",question:"The contract was _____ complex for a non-lawyer to understand easily.",options:["A) very","B) quite","C) too","D) enough"],answer:"C",explanation:"'Too complex for...to' — difficulty structure.",category:"Grammar"},
  {id:"p5e2_31",question:"_____ the manager nor the assistant was in the office yesterday.",options:["A) Both","B) Either","C) Neither","D) Not"],answer:"C",explanation:"'Neither...nor' for two subjects both not doing something.",category:"Grammar"},
  {id:"p5e2_32",question:"_____ employees are required to complete the e-learning modules.",options:["A) All","B) Every","C) Each","D) Both"],answer:"A",explanation:"'All employees' — 'all' used before plural nouns without 'of'.",category:"Grammar"},
  {id:"p5e2_33",question:"You can pay _____ cash or credit card.",options:["A) with either","B) neither","C) both","D) each"],answer:"A",explanation:"'Either...or' — a choice between two options.",category:"Grammar"},
  {id:"p5e2_34",question:"_____ the CEO and the CFO attended the investor day.",options:["A) Neither","B) Both","C) Either","D) Each"],answer:"B",explanation:"'Both...and' — two people, both included.",category:"Grammar"},
  {id:"p5e2_35",question:"_____ department must submit a monthly report.",options:["A) All","B) Both","C) Every","D) Either"],answer:"C",explanation:"'Every department' — used with singular nouns for 'all members of a group'.",category:"Grammar"},
  {id:"p5e2_36",question:"He used _____ commute by train, but he now drives to work.",options:["A) to","B) for","C) at","D) by"],answer:"A",explanation:"'Used to commute' — past habit that no longer exists.",category:"Grammar"},
  {id:"p5e2_37",question:"She is used _____ working late; she has done it for years.",options:["A) to","B) for","C) by","D) in"],answer:"A",explanation:"'Used to + gerund' — accustomed to something.",category:"Grammar"},
  {id:"p5e2_38",question:"The new system took getting _____ to, but it is now much faster.",options:["A) used","B) accustomed","C) familiar","D) both A and B"],answer:"A",explanation:"'Getting used to' = becoming accustomed to.",category:"Grammar"},
  {id:"p5e2_39",question:"I am not used _____ giving presentations, so I was quite nervous.",options:["A) to","B) for","C) of","D) with"],answer:"A",explanation:"'Used to + gerund' — comfortable with.",category:"Grammar"},
  {id:"p5e2_40",question:"The company _____ outsource most of its HR functions, but it now has an in-house team.",options:["A) uses to","B) used to","C) is used to","D) was used to"],answer:"B",explanation:"'Used to outsource' — past habit that has changed.",category:"Grammar"},
  {id:"p5e2_41",question:"I _____ the printer set up for the presentation.",options:["A) got","B) made","C) let","D) had"],answer:"D",explanation:"'Had the printer set up' — causative with past participle.",category:"Grammar"},
  {id:"p5e2_42",question:"She _____ her assistant book all the flights in advance.",options:["A) made","B) had","C) let","D) both B and C"],answer:"D",explanation:"'Had her assistant book' (arranged for) and 'let her assistant book' (permitted) are both valid.",category:"Grammar"},
  {id:"p5e2_43",question:"The manager _____ the entire team work overtime that weekend.",options:["A) made","B) had","C) let","D) allowed"],answer:"A",explanation:"'Made + object + base infinitive' — to force someone to do something.",category:"Grammar"},
  {id:"p5e2_44",question:"We _____ our website redesigned by a professional agency.",options:["A) had","B) made","C) let","D) got"],answer:"D",explanation:"'Got our website redesigned' — causative 'get + object + past participle'.",category:"Grammar"},
  {id:"p5e2_45",question:"He _____ the IT team fix the issue immediately.",options:["A) had","B) made","C) let","D) got"],answer:"A",explanation:"'Had the IT team fix' — causative arrangement.",category:"Grammar"},
  {id:"p5e2_46",question:"The conference _____ place in Singapore this year.",options:["A) took","B) takes","C) has taken","D) taking"],answer:"A",explanation:"Simple past — conference occurred in a specific past year.",category:"Grammar"},
  {id:"p5e2_47",question:"She gave _____ smoking after the doctor's advice.",options:["A) up","B) in","C) out","D) over"],answer:"A",explanation:"'Gave up' = stopped doing something.",category:"Phrasal Verb"},
  {id:"p5e2_48",question:"The board decided to take _____ a new strategic partner.",options:["A) on","B) in","C) up","D) off"],answer:"A",explanation:"'Take on' = bring on board / accept.",category:"Phrasal Verb"},
  {id:"p5e2_49",question:"The intern was asked to sort _____ the files in the archive room.",options:["A) out","B) through","C) up","D) both A and B"],answer:"D",explanation:"'Sort out' (organize/resolve) and 'sort through' (go through) are both valid.",category:"Phrasal Verb"},
  {id:"p5e2_50",question:"The supervisor had to step _____ as team leader due to a health issue.",options:["A) back","B) down","C) away","D) both B and C"],answer:"D",explanation:"'Step down' and 'step back' (from) both mean to resign from a position.",category:"Phrasal Verb"},
  {id:"p5e2_51",question:"The flight was delayed _____ three hours due to fog.",options:["A) for","B) by","C) during","D) in"],answer:"B",explanation:"'Delayed by' — indicates the amount of delay.",category:"Preposition"},
  {id:"p5e2_52",question:"She is responsible _____ overseeing the daily operations of the branch.",options:["A) for","B) of","C) with","D) to"],answer:"A",explanation:"'Responsible for' is the correct prepositional phrase.",category:"Preposition"},
  {id:"p5e2_53",question:"The decision was made _____ consultation with all stakeholders.",options:["A) in","B) after","C) with","D) both A and C"],answer:"D",explanation:"'In consultation with' and 'after consultation with' are both standard business phrases.",category:"Preposition"},
  {id:"p5e2_54",question:"The manager was pleased _____ the team's progress.",options:["A) at","B) by","C) with","D) both B and C"],answer:"D",explanation:"'Pleased with' and 'pleased by' are both acceptable.",category:"Preposition"},
  {id:"p5e2_55",question:"The policy is aimed _____ reducing unnecessary spending.",options:["A) for","B) at","C) to","D) toward"],answer:"B",explanation:"'Aimed at' = designed to achieve.",category:"Preposition"},
  {id:"p5e2_56",question:"She apologized _____ the delay in responding to the client.",options:["A) about","B) for","C) of","D) to"],answer:"B",explanation:"'Apologize for' = express regret about.",category:"Preposition"},
  {id:"p5e2_57",question:"Please inform us _____ any changes to your schedule.",options:["A) about","B) of","C) on","D) both A and B"],answer:"D",explanation:"'Inform about' and 'inform of' are both correct.",category:"Preposition"},
  {id:"p5e2_58",question:"He was promoted _____ Deputy General Manager last quarter.",options:["A) as","B) to","C) into","D) both B and C"],answer:"B",explanation:"'Promoted to [title]' is the standard expression.",category:"Preposition"},
  {id:"p5e2_59",question:"The new policy applies _____ all employees, regardless of seniority.",options:["A) for","B) at","C) to","D) with"],answer:"C",explanation:"'Applies to' = is relevant to / affects.",category:"Preposition"},
  {id:"p5e2_60",question:"The team was divided _____ opinion on the new marketing strategy.",options:["A) about","B) in","C) on","D) over"],answer:"D",explanation:"'Divided over' or 'divided on' — split in views about something.",category:"Preposition"},
  {id:"p5e2_61",question:"All files must be _____ in clearly labeled folders.",options:["A) store","B) stored","C) storing","D) stores"],answer:"B",explanation:"'Must be stored' — passive modal.",category:"Grammar"},
  {id:"p5e2_62",question:"The training _____ three days and covers all key software features.",options:["A) lasts","B) last","C) lasted","D) lasting"],answer:"A",explanation:"Present simple for a program's fixed duration.",category:"Grammar"},
  {id:"p5e2_63",question:"The office _____ renovated while staff worked from home.",options:["A) was","B) is","C) were","D) had"],answer:"A",explanation:"Simple passive past for a completed renovation.",category:"Grammar"},
  {id:"p5e2_64",question:"She had her business card _____ in three languages.",options:["A) print","B) prints","C) printed","D) printing"],answer:"C",explanation:"'Had it printed' — causative with past participle.",category:"Grammar"},
  {id:"p5e2_65",question:"The flight _____ at 7:45 AM, so please arrive at the airport early.",options:["A) leaves","B) leave","C) is leaving","D) both A and C"],answer:"D",explanation:"Present simple (schedule) and present continuous (imminent plan) are both correct.",category:"Grammar"},
  {id:"p5e2_66",question:"There are _____ seats available in the auditorium.",options:["A) few","B) a few","C) little","D) a little"],answer:"B",explanation:"'A few seats' — positive meaning, countable noun.",category:"Grammar"},
  {id:"p5e2_67",question:"We have _____ time before the deadline; let's not rush.",options:["A) a few","B) few","C) a little","D) little"],answer:"C",explanation:"'A little time' — some time remaining, uncountable.",category:"Grammar"},
  {id:"p5e2_68",question:"Unfortunately, there is _____ parking available near the venue.",options:["A) few","B) a few","C) little","D) a little"],answer:"C",explanation:"'Little parking' — very small amount, uncountable (negative implication).",category:"Grammar"},
  {id:"p5e2_69",question:"_____ employees know the full details of the acquisition.",options:["A) Little","B) Few","C) A little","D) A few"],answer:"B",explanation:"'Few employees' — very few, negative implication, countable.",category:"Grammar"},
  {id:"p5e2_70",question:"She has _____ experience with project management software.",options:["A) few","B) a few","C) a little","D) little"],answer:"C",explanation:"'A little experience' — some experience, positive, uncountable.",category:"Grammar"},
  {id:"p5e2_71",question:"The CEO's speech was _____ and to the point.",options:["A) brief","B) briefly","C) brevity","D) briefing"],answer:"A",explanation:"'Brief and to the point' — adjective in a compound predicate.",category:"Word Form"},
  {id:"p5e2_72",question:"The results were _____ better than the team had expected.",options:["A) considerable","B) considerably","C) considerate","D) considered"],answer:"B",explanation:"'Considerably better' — adverb modifying an adjective.",category:"Word Form"},
  {id:"p5e2_73",question:"Her _____ attention to detail makes her ideal for quality control.",options:["A) keen","B) keenly","C) keenness","D) keened"],answer:"A",explanation:"'Keen attention' — adjective modifying the noun.",category:"Word Form"},
  {id:"p5e2_74",question:"The product has been _____ redesigned to improve user experience.",options:["A) complete","B) completely","C) completion","D) completed"],answer:"B",explanation:"'Completely redesigned' — adverb modifying the past participle.",category:"Word Form"},
  {id:"p5e2_75",question:"The manager provided a _____ explanation of the new procedures.",options:["A) clear","B) clearly","C) clarity","D) clarify"],answer:"A",explanation:"'Clear explanation' — adjective modifying the noun.",category:"Word Form"},
  {id:"p5e2_76",question:"I would like to _____ our meeting from Monday to Wednesday.",options:["A) move","B) shift","C) change","D) all of the above"],answer:"D",explanation:"'Move', 'shift', and 'change' can all be used to reschedule a meeting.",category:"Vocabulary"},
  {id:"p5e2_77",question:"Could you _____ me with the sales figures by end of day?",options:["A) provide","B) supply","C) send","D) all of the above"],answer:"D",explanation:"'Provide', 'supply', and 'send' are all valid for sharing information.",category:"Vocabulary"},
  {id:"p5e2_78",question:"The company will _____ a new benefits package to all staff next quarter.",options:["A) roll out","B) introduce","C) launch","D) all of the above"],answer:"D",explanation:"'Roll out', 'introduce', and 'launch' all describe releasing something new.",category:"Vocabulary"},
  {id:"p5e2_79",question:"The department will _____ three more engineers before the year-end.",options:["A) hire","B) recruit","C) onboard","D) all of the above"],answer:"D",explanation:"'Hire', 'recruit', and 'onboard' all relate to bringing in new staff.",category:"Vocabulary"},
  {id:"p5e2_80",question:"She asked her assistant to _____ all the meeting notes from this week.",options:["A) compile","B) gather","C) collate","D) all of the above"],answer:"D",explanation:"'Compile', 'gather', and 'collate' all mean to bring together information.",category:"Vocabulary"},
  {id:"p5e2_81",question:"The office _____ at 5:00 PM on weekdays and 1:00 PM on Saturdays.",options:["A) close","B) closes","C) is closing","D) will close"],answer:"B",explanation:"Present simple for regular schedules.",category:"Grammar"},
  {id:"p5e2_82",question:"She has been _____ to the London office for the next two months.",options:["A) assigned","B) allocate","C) send","D) placing"],answer:"A",explanation:"'Been assigned to' — present perfect passive for a recent decision.",category:"Grammar"},
  {id:"p5e2_83",question:"The equipment must be returned _____ good working condition.",options:["A) in","B) at","C) on","D) with"],answer:"A",explanation:"'In good working condition' is a fixed expression.",category:"Preposition"},
  {id:"p5e2_84",question:"The survey will take _____ five minutes to complete.",options:["A) approximate","B) approximately","C) approximation","D) approximated"],answer:"B",explanation:"'Approximately five minutes' — adverb modifying the noun phrase.",category:"Word Form"},
  {id:"p5e2_85",question:"_____ you have any questions, please do not hesitate to contact us.",options:["A) Whether","B) Unless","C) Should","D) Whenever"],answer:"C",explanation:"'Should you have any questions' = 'If you have any questions' — formal conditional inversion.",category:"Grammar"},
  {id:"p5e2_86",question:"The printer runs _____ ink; could someone order a new cartridge?",options:["A) low in","B) low on","C) out of","D) both B and C"],answer:"D",explanation:"'Running low on' and 'running out of' both describe depleting supplies.",category:"Vocabulary"},
  {id:"p5e2_87",question:"The supervisor _____ approval for all purchases over $500.",options:["A) must give","B) must be given","C) must grant","D) both A and C"],answer:"D",explanation:"'Must give approval' (supervisor authorizes) and 'must grant approval' are both correct.",category:"Grammar"},
  {id:"p5e2_88",question:"The IT helpdesk is available _____ the clock.",options:["A) at","B) around","C) round","D) both B and C"],answer:"D",explanation:"'Around the clock' and 'round the clock' both mean 24 hours a day.",category:"Vocabulary"},
  {id:"p5e2_89",question:"Please keep all correspondence _____ future reference.",options:["A) to","B) for","C) of","D) at"],answer:"B",explanation:"'For future reference' = to use or refer to later.",category:"Preposition"},
  {id:"p5e2_90",question:"The team _____ their best effort into the project and it showed.",options:["A) put","B) gave","C) poured","D) all of the above"],answer:"D",explanation:"'Put', 'gave', and 'poured' their best effort are all natural expressions.",category:"Vocabulary"},
  {id:"p5e2_91",question:"The report must be _____ by 5 PM without exception.",options:["A) hand in","B) handed in","C) handing in","D) hand out"],answer:"B",explanation:"'Handed in' — passive past participle after 'must be'.",category:"Grammar"},
  {id:"p5e2_92",question:"The new hire showed great _____ on her first day.",options:["A) initiative","B) initiate","C) initiating","D) initiated"],answer:"A",explanation:"'Showed great initiative' — noun as object.",category:"Vocabulary"},
  {id:"p5e2_93",question:"Parking is _____ outside the main building between 7 AM and 9 AM.",options:["A) restricted","B) restricting","C) restrict","D) restriction"],answer:"A",explanation:"'Parking is restricted' — passive adjective.",category:"Grammar"},
  {id:"p5e2_94",question:"Could you please _____ the key points of the meeting for those who couldn't attend?",options:["A) summarize","B) recap","C) outline","D) all of the above"],answer:"D",explanation:"'Summarize', 'recap', and 'outline' all mean to give a brief overview.",category:"Vocabulary"},
  {id:"p5e2_95",question:"The team met _____ target for the third consecutive quarter.",options:["A) its","B) their","C) the","D) both A and B"],answer:"D",explanation:"'Met its target' (team as singular) and 'met their target' (team as plural) are both accepted.",category:"Grammar"},
  {id:"p5e2_96",question:"The guest speaker has _____ 30 years of experience in international trade.",options:["A) more than","B) over","C) upwards of","D) all of the above"],answer:"D",explanation:"'More than', 'over', and 'upwards of' all express exceeding a quantity.",category:"Vocabulary"},
  {id:"p5e2_97",question:"Please _____ your seat belt before the vehicle moves.",options:["A) fasten","B) wear","C) put on","D) both A and C"],answer:"D",explanation:"'Fasten' and 'put on' your seat belt are both correct.",category:"Vocabulary"},
  {id:"p5e2_98",question:"The annual report _____ published on the company website every March.",options:["A) is","B) was","C) were","D) are"],answer:"A",explanation:"Present simple passive for a regular recurring action.",category:"Grammar"},
  {id:"p5e2_99",question:"He _____ his job because the company offered him a better position.",options:["A) left","B) quit","C) resigned from","D) all of the above"],answer:"D",explanation:"'Left', 'quit', and 'resigned from' all describe voluntarily leaving a job.",category:"Vocabulary"},
  {id:"p5e2_100",question:"The lunch break is _____ one hour every day.",options:["A) by","B) of","C) for","D) lasting"],answer:"C",explanation:"'For one hour' — duration preposition.",category:"Preposition"},
  {id:"p5e2_101",question:"The building is _____ the subway station, just a five-minute walk.",options:["A) close to","B) near","C) next to","D) both A and B"],answer:"D",explanation:"'Close to' and 'near' both indicate proximity.",category:"Preposition"},
  {id:"p5e2_102",question:"Please _____ this email to everyone in the distribution list.",options:["A) forward","B) send","C) copy","D) all of the above"],answer:"D",explanation:"'Forward', 'send', and 'copy' are all valid for distributing an email.",category:"Vocabulary"},
  {id:"p5e2_103",question:"The budget proposal is due _____ the end of the fiscal year.",options:["A) until","B) by","C) before","D) both B and C"],answer:"D",explanation:"'By' and 'before' the end both indicate a deadline.",category:"Preposition"},
  {id:"p5e2_104",question:"Her work has been _____ praised by the entire management team.",options:["A) high","B) highly","C) higher","D) highest"],answer:"B",explanation:"'Highly praised' — adverb modifying the past participle.",category:"Word Form"},
  {id:"p5e2_105",question:"The client was _____ satisfied with the service provided.",options:["A) complete","B) completely","C) completion","D) completed"],answer:"B",explanation:"'Completely satisfied' — adverb modifying the adjective.",category:"Word Form"},
  {id:"p5e2_106",question:"The conference call _____ at 10 AM and ended at 11:30 AM.",options:["A) starts","B) started","C) has started","D) is starting"],answer:"B",explanation:"Simple past for a completed event.",category:"Grammar"},
  {id:"p5e2_107",question:"She _____ the company for 20 years before retiring last year.",options:["A) has worked","B) is working","C) had worked","D) was working"],answer:"C",explanation:"Past perfect 'had worked' for an action completed before another past action.",category:"Grammar"},
  {id:"p5e2_108",question:"The training room is _____ for groups of up to 30 participants.",options:["A) capable","B) suitable","C) able","D) fitting"],answer:"B",explanation:"'Suitable for' = appropriate for the purpose.",category:"Vocabulary"},
  {id:"p5e2_109",question:"We are _____ a solution to the supply chain issue.",options:["A) working on","B) working at","C) working for","D) working by"],answer:"A",explanation:"'Working on a solution' = actively trying to solve it.",category:"Vocabulary"},
  {id:"p5e2_110",question:"The shop will be closed _____ renovation from Monday to Wednesday.",options:["A) for","B) during","C) throughout","D) all of the above"],answer:"D",explanation:"'For', 'during', and 'throughout' renovation are all valid.",category:"Preposition"},
  {id:"p5e2_111",question:"The proposal needs to be _____ before we submit it to the board.",options:["A) proofread","B) polished","C) refined","D) all of the above"],answer:"D",explanation:"'Proofread', 'polished', and 'refined' all mean to improve a document.",category:"Vocabulary"},
  {id:"p5e2_112",question:"There is _____ need to attend if you have already reviewed the materials.",options:["A) no","B) not any","C) not a","D) both A and B"],answer:"D",explanation:"'No need' and 'not any need' are both grammatically correct.",category:"Grammar"},
  {id:"p5e2_113",question:"The company _____ provide reimbursement for travel-related expenses.",options:["A) does","B) will","C) can","D) all of the above"],answer:"D",explanation:"'Does', 'will', and 'can provide' are all valid depending on tense context.",category:"Grammar"},
  {id:"p5e2_114",question:"The technician _____ the issue in less than an hour.",options:["A) fixing","B) fixed","C) was fixing","D) has fixed"],answer:"B",explanation:"Simple past for a completed repair.",category:"Grammar"},
  {id:"p5e2_115",question:"She was the _____ person to arrive at the meeting.",options:["A) later","B) lately","C) last","D) latest"],answer:"C",explanation:"'The last person' = the final one to arrive.",category:"Vocabulary"},
  {id:"p5e2_116",question:"The promotion was given _____ someone with more experience.",options:["A) for","B) to","C) at","D) toward"],answer:"B",explanation:"'Given to someone' — indirect object with 'to'.",category:"Preposition"},
  {id:"p5e2_117",question:"The results _____ our expectations by a wide margin.",options:["A) exceed","B) exceeded","C) were exceeding","D) are exceeded"],answer:"B",explanation:"Simple past for a completed event.",category:"Grammar"},
  {id:"p5e2_118",question:"The new catalog is available _____ free of charge.",options:["A) from","B) for","C) at","D) as"],answer:"B",explanation:"'Available for free' or 'free of charge'.",category:"Preposition"},
  {id:"p5e2_119",question:"All applications must be _____ before the deadline.",options:["A) submit","B) submitting","C) submitted","D) submits"],answer:"C",explanation:"'Must be submitted' — passive modal for requirement.",category:"Grammar"},
  {id:"p5e2_120",question:"The department had a _____ meeting to discuss the quarterly results.",options:["A) brief","B) shortly","C) short","D) both A and C"],answer:"D",explanation:"'Brief meeting' and 'short meeting' are both correct.",category:"Vocabulary"},
  {id:"p5e2_121",question:"She works in the _____ department and handles all invoices.",options:["A) account","B) accounts","C) accounting","D) both B and C"],answer:"D",explanation:"'Accounts department' and 'accounting department' are both standard.",category:"Vocabulary"},
  {id:"p5e2_122",question:"Please let me know _____ you can attend the session.",options:["A) when","B) if","C) whether","D) both B and C"],answer:"D",explanation:"'If' and 'whether' are interchangeable in indirect yes/no questions.",category:"Grammar"},
  {id:"p5e2_123",question:"The supplier offered a _____ of five percent for early payment.",options:["A) discount","B) rebate","C) reduction","D) all of the above"],answer:"D",explanation:"'Discount', 'rebate', and 'reduction' all describe a price reduction.",category:"Vocabulary"},
  {id:"p5e2_124",question:"The new receptionist _____ visitors with a warm welcome every day.",options:["A) greet","B) greets","C) greeted","D) greeting"],answer:"B",explanation:"Third-person singular present simple for a habitual action.",category:"Grammar"},
  {id:"p5e2_125",question:"He forgot _____ the meeting invitation, so nobody received the calendar event.",options:["A) to send","B) sending","C) send","D) to sending"],answer:"A",explanation:"'Forgot to send' = he intended to but didn't (infinitive after 'forget').",category:"Grammar"},
  {id:"p5e2_126",question:"I remember _____ this client last year at the trade fair.",options:["A) to meet","B) meeting","C) meet","D) met"],answer:"B",explanation:"'Remember + gerund' = recall a past event.",category:"Grammar"},
  {id:"p5e2_127",question:"They stopped _____ new staff due to budget constraints.",options:["A) hire","B) to hire","C) hiring","D) hired"],answer:"C",explanation:"'Stopped hiring' = ceased the activity.",category:"Grammar"},
  {id:"p5e2_128",question:"The manager tried _____ the client, but the call kept dropping.",options:["A) to call","B) calling","C) call","D) both A and B"],answer:"D",explanation:"'Tried to call' (made an attempt) and 'tried calling' (attempted the method) are both valid.",category:"Grammar"},
  {id:"p5e2_129",question:"She regrets _____ the job offer; the company grew significantly.",options:["A) to reject","B) rejecting","C) rejected","D) reject"],answer:"B",explanation:"'Regrets + gerund' = is sorry about something in the past.",category:"Grammar"},
  {id:"p5e2_130",question:"He went on _____ even after everyone else had finished.",options:["A) talk","B) talking","C) to talk","D) talked"],answer:"B",explanation:"'Went on talking' = continued doing the same thing.",category:"Grammar"},
  {id:"p5e2_131",question:"The proposal needs more work; _____, I suggest we revise it before submitting.",options:["A) therefore","B) however","C) although","D) despite"],answer:"A",explanation:"'Therefore' signals a logical conclusion.",category:"Connector"},
  {id:"p5e2_132",question:"Sales were below target; _____, management remained optimistic.",options:["A) therefore","B) furthermore","C) however","D) since"],answer:"C",explanation:"'However' introduces a contrasting idea.",category:"Connector"},
  {id:"p5e2_133",question:"The new policy reduces costs; _____, it improves efficiency.",options:["A) however","B) furthermore","C) despite","D) unless"],answer:"B",explanation:"'Furthermore' adds another supporting point.",category:"Connector"},
  {id:"p5e2_134",question:"We have met the deadline; _____, all deliverables have been approved.",options:["A) moreover","B) in addition","C) furthermore","D) all of the above"],answer:"D",explanation:"'Moreover', 'in addition', and 'furthermore' all add positive supporting information.",category:"Connector"},
  {id:"p5e2_135",question:"The client was unhappy; _____, we offered a full refund.",options:["A) consequently","B) as a result","C) therefore","D) all of the above"],answer:"D",explanation:"'Consequently', 'as a result', and 'therefore' all introduce a consequence.",category:"Connector"},
  {id:"p5e2_136",question:"He works full-time _____ studying for his MBA.",options:["A) while","B) during","C) as","D) both A and C"],answer:"D",explanation:"'While studying' and 'as studying' (less common) both indicate simultaneous actions.",category:"Grammar"},
  {id:"p5e2_137",question:"_____ arriving at the hotel, please call the conference organizer.",options:["A) After","B) Upon","C) Following","D) all of the above"],answer:"D",explanation:"'After', 'upon', and 'following' all indicate sequence of events.",category:"Grammar"},
  {id:"p5e2_138",question:"The team finished ahead of schedule, _____ saved significant costs.",options:["A) which","B) that","C) what","D) how"],answer:"A",explanation:"'Which saved' — non-defining relative clause referring to the whole idea.",category:"Grammar"},
  {id:"p5e2_139",question:"The employee _____ complained repeatedly was eventually transferred.",options:["A) who","B) whom","C) whose","D) which"],answer:"A",explanation:"'Employee who complained' — relative pronoun for a person as subject.",category:"Grammar"},
  {id:"p5e2_140",question:"The report, _____ I sent you last week, contains all the key figures.",options:["A) that","B) which","C) what","D) who"],answer:"B",explanation:"'Which I sent' — non-defining relative clause (note comma) uses 'which'.",category:"Grammar"},
  {id:"p5e2_141",question:"The team leader _____ email address is on the board will answer your questions.",options:["A) which","B) who","C) whose","D) whom"],answer:"C",explanation:"'Whose email address' — possessive relative pronoun.",category:"Grammar"},
  {id:"p5e2_142",question:"The building _____ we hold our training sessions has excellent facilities.",options:["A) which","B) where","C) that","D) both A and B"],answer:"D",explanation:"'The building which/that we hold sessions in' or 'the building where we hold sessions'.",category:"Grammar"},
  {id:"p5e2_143",question:"That was the year _____ the company celebrated its 50th anniversary.",options:["A) which","B) where","C) when","D) that"],answer:"C",explanation:"'The year when' — relative adverb for time.",category:"Grammar"},
  {id:"p5e2_144",question:"Please send the parcel to the address _____ I provided earlier.",options:["A) that","B) which","C) where","D) both A and B"],answer:"D",explanation:"'The address that/which I provided' — defining relative clause; both work.",category:"Grammar"},
  {id:"p5e2_145",question:"_____ by the client's praise, the team redoubled their efforts.",options:["A) Encouraged","B) Encouraging","C) To encourage","D) Encouragement"],answer:"A",explanation:"'Encouraged by' — passive participle clause modifying the subject.",category:"Grammar"},
  {id:"p5e2_146",question:"_____ the new pricing structure, the marketing team updated all materials.",options:["A) Announcing","B) Having announced","C) Being announced","D) Announced"],answer:"B",explanation:"'Having announced' — perfect participle for the completed action that came first.",category:"Grammar"},
  {id:"p5e2_147",question:"_____ with multiple complaints, the manager arranged an urgent meeting.",options:["A) Facing","B) Faced","C) To face","D) Having faced"],answer:"B",explanation:"'Faced with' — passive participle as a reduced clause ('being faced with').",category:"Grammar"},
  {id:"p5e2_148",question:"The client called to confirm _____ the order had been shipped.",options:["A) if","B) whether","C) that","D) all of the above"],answer:"D",explanation:"'Confirm if / whether / that' — all correct after 'confirm'.",category:"Grammar"},
  {id:"p5e2_149",question:"Please advise _____ you prefer the Monday or Tuesday delivery slot.",options:["A) if","B) whether","C) both A and B","D) that"],answer:"C",explanation:"'Advise if/whether' — indirect question with either conjunction.",category:"Grammar"},
  {id:"p5e2_150",question:"The manager wasn't sure _____ to handle the sensitive complaint.",options:["A) what","B) how","C) when","D) both A and B"],answer:"B",explanation:"'Wasn't sure how to handle' — indirect question with 'how'.",category:"Grammar"},
  {id:"p5e2_151",question:"We couldn't decide _____ to hold the event indoors or outdoors.",options:["A) whether","B) if","C) how","D) what"],answer:"A",explanation:"'Decide whether to' — 'whether' in infinitive clauses.",category:"Grammar"},
  {id:"p5e2_152",question:"He told me _____ to worry; the issue was already resolved.",options:["A) don't","B) not","C) no","D) didn't"],answer:"B",explanation:"'Told me not to worry' — indirect imperative uses 'not to'.",category:"Grammar"},
  {id:"p5e2_153",question:"She said that she _____ the report the following morning.",options:["A) will submit","B) would submit","C) submits","D) has submitted"],answer:"B",explanation:"Reported speech: 'will' changes to 'would'.",category:"Grammar"},
  {id:"p5e2_154",question:"He told me he _____ the job offer earlier that week.",options:["A) accepted","B) has accepted","C) had accepted","D) would accept"],answer:"C",explanation:"Reported speech: past action reported in past = past perfect.",category:"Grammar"},
  {id:"p5e2_155",question:"The manager asked if I _____ available for a call the next day.",options:["A) am","B) was","C) were","D) both B and C"],answer:"D",explanation:"Indirect question in past: 'if I was/were available'.",category:"Grammar"},
  {id:"p5e2_156",question:"She announced that the company _____ a new product that month.",options:["A) launched","B) was launching","C) had launched","D) both B and C"],answer:"D",explanation:"'Was launching' (in progress at the time) and 'had launched' (already complete) are both valid.",category:"Grammar"},
  {id:"p5e2_157",question:"The technician _____ the printer is working fine now.",options:["A) tells","B) said","C) reported","D) confirmed"],answer:"D",explanation:"'Confirmed the printer is working' — most precise for verifying something.",category:"Vocabulary"},
  {id:"p5e2_158",question:"He proposed _____ the budget for the next fiscal year.",options:["A) to increase","B) increasing","C) an increase in","D) all of the above"],answer:"D",explanation:"'Proposed to increase', 'proposed increasing', and 'proposed an increase in' are all correct.",category:"Grammar"},
  {id:"p5e2_159",question:"The assistant reminded everyone _____ bring their ID to the AGM.",options:["A) to","B) of","C) that","D) both A and C"],answer:"D",explanation:"'Reminded everyone to bring' and 'reminded everyone that they should bring' are both correct.",category:"Grammar"},
  {id:"p5e2_160",question:"Management insisted _____ all costs be kept below $10,000.",options:["A) that","B) on","C) for","D) both A and B"],answer:"D",explanation:"'Insisted that' (subjunctive) and 'insisted on' (preposition) are both correct.",category:"Grammar"},
  {id:"p5e2_161",question:"The company _____ hiring decisions based on skills, not just qualifications.",options:["A) makes","B) takes","C) does","D) both A and B"],answer:"A",explanation:"'Makes hiring decisions' — 'make' is the correct verb with 'decisions'.",category:"Vocabulary"},
  {id:"p5e2_162",question:"She has _____ a strong reputation for delivering projects on time.",options:["A) built","B) built up","C) developed","D) all of the above"],answer:"D",explanation:"'Built', 'built up', and 'developed a reputation' are all correct.",category:"Vocabulary"},
  {id:"p5e2_163",question:"The supplier was _____ to deliver the components by the agreed date.",options:["A) unable","B) incapable","C) not capable","D) all of the above"],answer:"D",explanation:"'Unable', 'incapable', and 'not capable' all indicate inability to deliver.",category:"Vocabulary"},
  {id:"p5e2_164",question:"The manager _____ the team's efforts at the quarterly awards ceremony.",options:["A) acknowledged","B) recognized","C) appreciated","D) all of the above"],answer:"D",explanation:"'Acknowledged', 'recognized', and 'appreciated' all describe formally thanking a team.",category:"Vocabulary"},
  {id:"p5e2_165",question:"The data shows that customer _____ has improved by 12% this year.",options:["A) satisfy","B) satisfying","C) satisfaction","D) satisfied"],answer:"C",explanation:"'Customer satisfaction' — noun compound.",category:"Word Form"},
  {id:"p5e2_166",question:"The company has a strict no-_____ policy in the workplace.",options:["A) discrimination","B) harassment","C) bullying","D) all of the above"],answer:"D",explanation:"'Discrimination', 'harassment', and 'bullying' are all workplace policy terms.",category:"Vocabulary"},
  {id:"p5e2_167",question:"Please cc the finance team on all _____ relating to invoice payments.",options:["A) correspondence","B) emails","C) communications","D) all of the above"],answer:"D",explanation:"'Correspondence', 'emails', and 'communications' can all be cc'd.",category:"Vocabulary"},
  {id:"p5e2_168",question:"I am writing _____ regard to your application submitted last week.",options:["A) in","B) with","C) regarding","D) both A and B"],answer:"D",explanation:"'In regard to' and 'with regard to' are both correct formal expressions.",category:"Preposition"},
  {id:"p5e2_169",question:"_____ order to meet the deadline, the team worked through the weekend.",options:["A) In","B) By","C) For","D) With"],answer:"A",explanation:"'In order to' = for the purpose of.",category:"Connector"},
  {id:"p5e2_170",question:"The new system was implemented _____ the aim of reducing processing time.",options:["A) for","B) with","C) in","D) both A and B"],answer:"D",explanation:"'For the aim of' and 'with the aim of' are both used, though 'with the aim of' is more common.",category:"Preposition"},
  {id:"p5e2_171",question:"He _____ the project from start to finish without any assistance.",options:["A) handled","B) managed","C) oversaw","D) all of the above"],answer:"D",explanation:"'Handled', 'managed', and 'oversaw' all describe leading a project independently.",category:"Vocabulary"},
  {id:"p5e2_172",question:"The company _____ on its clients' trust to sustain its business.",options:["A) relies","B) depends","C) counts","D) all of the above"],answer:"D",explanation:"'Relies on', 'depends on', and 'counts on' all mean to need something.",category:"Vocabulary"},
  {id:"p5e2_173",question:"The project is _____ schedule and within budget.",options:["A) on","B) in","C) at","D) by"],answer:"A",explanation:"'On schedule' = progressing as planned.",category:"Preposition"},
  {id:"p5e2_174",question:"The sales figures have been _____ steadily over the past six months.",options:["A) grow","B) grew","C) growing","D) grown"],answer:"C",explanation:"'Have been growing' — present perfect continuous for an ongoing trend.",category:"Grammar"},
  {id:"p5e2_175",question:"She _____ the report when her computer crashed and she lost all her work.",options:["A) writes","B) wrote","C) was writing","D) had written"],answer:"C",explanation:"Past continuous for an action interrupted by another event.",category:"Grammar"},
  {id:"p5e2_176",question:"_____ the demand, the company hired 50 more customer service agents.",options:["A) Meeting","B) To meet","C) In meeting","D) both A and B"],answer:"D",explanation:"'To meet the demand' (purpose) and 'meeting the demand' (participial) are both grammatical.",category:"Grammar"},
  {id:"p5e2_177",question:"All staff are _____ to report any safety hazards immediately.",options:["A) urged","B) encouraged","C) requested","D) all of the above"],answer:"D",explanation:"'Urged', 'encouraged', and 'requested' all convey the message to report hazards.",category:"Vocabulary"},
  {id:"p5e2_178",question:"The CEO _____ a visit to the Singapore branch next month.",options:["A) is planning","B) plans","C) has planned","D) all of the above"],answer:"D",explanation:"'Is planning', 'plans', and 'has planned' a visit are all valid depending on context.",category:"Grammar"},
  {id:"p5e2_179",question:"The contract was signed in the _____ of two witnesses.",options:["A) presence","B) present","C) attendance","D) both A and C"],answer:"D",explanation:"'Presence of witnesses' and 'attendance of witnesses' are both standard legal language.",category:"Vocabulary"},
  {id:"p5e2_180",question:"The company offers _____ compensation for employees who work on public holidays.",options:["A) additional","B) extra","C) supplemental","D) all of the above"],answer:"D",explanation:"'Additional', 'extra', and 'supplemental' compensation are all correct.",category:"Vocabulary"},
  {id:"p5e2_181",question:"_____ the time the investigation concluded, the suspect had already left the country.",options:["A) By","B) Until","C) When","D) After"],answer:"A",explanation:"'By the time' indicates that the action was complete before a certain point.",category:"Grammar"},
  {id:"p5e2_182",question:"The marketing budget for next year has been _____ slightly.",options:["A) increase","B) increasing","C) increased","D) increment"],answer:"C",explanation:"'Has been increased' — present perfect passive.",category:"Grammar"},
  {id:"p5e2_183",question:"We aim to _____ the issue before the client's next visit.",options:["A) solve","B) resolve","C) fix","D) all of the above"],answer:"D",explanation:"'Solve', 'resolve', and 'fix' the issue are all valid.",category:"Vocabulary"},
  {id:"p5e2_184",question:"The company will donate 5% of its _____ profits to charity.",options:["A) annual","B) yearly","C) year's","D) both A and B"],answer:"D",explanation:"'Annual profits' and 'yearly profits' are interchangeable.",category:"Vocabulary"},
  {id:"p5e2_185",question:"Employees may park in the visitor lot _____ the main lot is full.",options:["A) when","B) if","C) in case","D) both A and B"],answer:"D",explanation:"'When' and 'if' the lot is full are both valid conditional expressions.",category:"Grammar"},
  {id:"p5e2_186",question:"The board has approved the plan _____ it is implemented by year-end.",options:["A) provided","B) providing","C) on condition","D) both A and B"],answer:"D",explanation:"'Provided' and 'providing' introduce conditions — both are standard.",category:"Grammar"},
  {id:"p5e2_187",question:"The new product will be available _____ order from our website.",options:["A) to","B) for","C) on","D) by"],answer:"C",explanation:"'Available on order' or 'available to order' — 'on' is more common in British English.",category:"Preposition"},
  {id:"p5e2_188",question:"The team leader sent the document _____ all members for review.",options:["A) to","B) for","C) at","D) toward"],answer:"A",explanation:"'Sent to all members' — indirect object with 'to'.",category:"Preposition"},
  {id:"p5e2_189",question:"We will _____ the final decision after consulting with all stakeholders.",options:["A) announce","B) make","C) reach","D) all of the above"],answer:"D",explanation:"'Announce', 'make', and 'reach' a final decision are all valid collocations.",category:"Vocabulary"},
  {id:"p5e2_190",question:"The manager _____ the team to achieve even better results next quarter.",options:["A) motivated","B) inspired","C) encouraged","D) all of the above"],answer:"D",explanation:"'Motivated', 'inspired', and 'encouraged' all describe lifting team morale.",category:"Vocabulary"},
  {id:"p5e2_191",question:"Could you _____ me how to access the shared drive?",options:["A) show","B) teach","C) demonstrate","D) all of the above"],answer:"D",explanation:"'Show', 'teach', and 'demonstrate to me how' are all correct.",category:"Vocabulary"},
  {id:"p5e2_192",question:"The client _____ the invoice within two days of receiving it.",options:["A) settled","B) paid","C) cleared","D) all of the above"],answer:"D",explanation:"'Settled', 'paid', and 'cleared' an invoice are all standard business terms.",category:"Vocabulary"},
  {id:"p5e2_193",question:"Please keep this information _____ until the official announcement.",options:["A) confidential","B) private","C) secret","D) all of the above"],answer:"D",explanation:"'Confidential', 'private', and 'secret' all mean not to share before the announcement.",category:"Vocabulary"},
  {id:"p5e2_194",question:"The report was _____ by the senior editor before publication.",options:["A) approved","B) endorsed","C) cleared","D) all of the above"],answer:"D",explanation:"'Approved', 'endorsed', and 'cleared' all mean formally authorized.",category:"Vocabulary"},
  {id:"p5e2_195",question:"The seminar covers the _____ skills needed for effective leadership.",options:["A) core","B) key","C) essential","D) all of the above"],answer:"D",explanation:"'Core', 'key', and 'essential' skills are all synonyms for most important.",category:"Vocabulary"},
  {id:"p5e2_196",question:"She was _____ for her contributions to the company over 20 years.",options:["A) honored","B) recognized","C) awarded","D) all of the above"],answer:"D",explanation:"'Honored', 'recognized', and 'awarded' describe formal acknowledgment.",category:"Vocabulary"},
  {id:"p5e2_197",question:"The manager had a _____ word with the employee after the incident.",options:["A) brief","B) quick","C) short","D) all of the above"],answer:"D",explanation:"'Brief word', 'quick word', and 'short word' are all common expressions for a brief conversation.",category:"Vocabulary"},
  {id:"p5e2_198",question:"We hope to _____ an agreement by the end of the current quarter.",options:["A) reach","B) conclude","C) finalize","D) all of the above"],answer:"D",explanation:"'Reach', 'conclude', and 'finalize' an agreement are all correct.",category:"Vocabulary"},
  {id:"p5e2_199",question:"The company _____ a team to investigate the cause of the data loss.",options:["A) assembled","B) formed","C) put together","D) all of the above"],answer:"D",explanation:"'Assembled', 'formed', and 'put together' a team are all natural expressions.",category:"Vocabulary"},
  {id:"p5e2_200",question:"The new cafeteria will _____ a wide variety of meals for all dietary needs.",options:["A) offer","B) provide","C) serve","D) all of the above"],answer:"D",explanation:"'Offer', 'provide', and 'serve' meals are all correct.",category:"Vocabulary"}
];
